create database if not exists meteosalle;
use meteosalle;
create table if not exists `user` (
    `id` int(11) NOT NULL AUTO_INCREMENT,
    `uuidUser` varchar(50) NOT NULL COMMENT 'identificador unico de usuario el algoritmo genera 50 caracteres de largo',
    `name` varchar(25) DEFAULT NULL,
    `lastname` varchar(35) DEFAULT NULL,
    `password` varchar(45) DEFAULT NULL,
    `userName` varchar(45) DEFAULT NULL,
    `age` tinyint(3) DEFAULT NULL,
    `gender` varchar(6) DEFAULT NULL COMMENT 'En el momento de creacion de la tabla se contemplaban escrituras male female, other',
    `deletedUser` char(1) DEFAULT '0',
    PRIMARY KEY (`id`),
    UNIQUE KEY `uuidUser_UNIQUE` (`uuidUser`),
    KEY `uuidUser_idx` (`uuidUser`)
    ) ENGINE=InnoDB AUTO_INCREMENT=36 DEFAULT CHARSET=utf8;


create table if not exists `station` (
    `id` int(11) NOT NULL AUTO_INCREMENT,
    `uuidStation` varchar(50) DEFAULT NULL,
    `uuidUser` varchar(50) DEFAULT NULL,
    `latitud` decimal(10,8) DEFAULT NULL COMMENT 'Las latitudes van de -90 a 90 (grados), por lo que DECIMAL (10, 8) ES MEJOR PARA HACER CALCULOS\\n https://codeday.me/es/qa/20181207/18421.html',
    `longitud` decimal(11,9) DEFAULT NULL COMMENT 'longitudes var铆an de -180 a 180 (grados), por lo que necesita DECIMAL (11, 8) https://codeday.me/es/qa/20181207/18421.html',
    `postalCode` char(6) DEFAULT NULL COMMENT 'Segun el listado de codigos postales de espa帽a',
    `temp` decimal(4,2) DEFAULT NULL,
    `humidity` decimal(4,2) DEFAULT NULL COMMENT 'llega hasta el 100 % de humedad, no se descarta que pueda tener decimales',
    `presion` decimal(6,2) DEFAULT NULL,
    `location` varchar(254) DEFAULT NULL,
    `timestamp` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
    `deletedStation` char(1) NOT NULL DEFAULT '0',
    `state` varchar(45) DEFAULT NULL,
    PRIMARY KEY (`id`),
    KEY `idx_uuidUser` (`uuidUser`),
    KEY `idx_uuidStation` (`uuidStation`),
    CONSTRAINT `fx_user` FOREIGN KEY (`uuidUser`) REFERENCES `user` (`uuidUser`) ON DELETE NO ACTION ON UPDATE NO ACTION
    ) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8;

create table if not exists `StationHistory` (
                                  `idStationHistory` int(11) NOT NULL AUTO_INCREMENT,
                                  `uuidStation` varchar(50) NOT NULL,
                                  `temp` decimal(4,2) DEFAULT NULL,
                                  `humidity` decimal(4,2) DEFAULT NULL,
                                  `presion` decimal(6,2) DEFAULT NULL,
                                  `timestamp` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
                                  PRIMARY KEY (`idStationHistory`),
                                  KEY `fx_station_idx` (`uuidStation`),
                                  KEY `idx_station` (`uuidStation`),
                                  CONSTRAINT `fx_station` FOREIGN KEY (`uuidStation`) REFERENCES `station` (`uuidStation`) ON DELETE NO ACTION ON UPDATE NO ACTION
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8;

